public class HybridWebView extends WebView {
    private Context context;
    private HybridBridge bridge;

    public HybridWebView(Context context) {
        super(context);
        this.context = context;
        initWebView();
    }

    public HybridWebView(Context context, AttributeSet attrs) {
        super(context, attrs);
        this.context = context;
        initWebView();
    }

    private void initWebView() {
        WebSettings webSettings = getSettings();
        webSettings.setJavaScriptEnabled(true);
        webSettings.setDomStorageEnabled(true);
        webSettings.setAllowFileAccess(true);
        webSettings.setAllowContentAccess(true);
        webSettings.setCacheMode(WebSettings.LOAD_DEFAULT);
        
        bridge = new HybridBridge(context);
        addJavascriptInterface(bridge, "AndroidBridge");
        
        setWebViewClient(new WebViewClient() {
            @Override
            public boolean shouldOverrideUrlLoading(WebView view, String url) {
                view.loadUrl(url);
                return true;
            }
        });
        
        loadUrl("https://your-mobile-website.com");
    }

    public class HybridBridge {
        private Context context;

        public HybridBridge(Context context) {
            this.context = context;
        }

        @JavascriptInterface
        public void openCamera() {
            Intent intent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
            if (context instanceof Activity) {
                ((Activity) context).startActivityForResult(intent, 1001);
            }
        }

        @JavascriptInterface
        public void getLocation() {
            LocationManager locationManager = (LocationManager) context.getSystemService(Context.LOCATION_SERVICE);
            if (ActivityCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED) {
                Location location = locationManager.getLastKnownLocation(LocationManager.GPS_PROVIDER);
                if (location != null) {
                    String locationData = location.getLatitude() + "," + location.getLongitude();
                    ((Activity) context).runOnUiThread(() -> {
                        loadUrl("javascript:receiveLocation('" + locationData + "')");
                    });
                }
            }
        }

        @JavascriptInterface
        public void makePayment(String amount, String currency) {
            // Implement payment logic here
            Intent intent = new Intent(context, PaymentActivity.class);
            intent.putExtra("amount", amount);
            intent.putExtra("currency", currency);
            if (context instanceof Activity) {
                ((Activity) context).startActivity(intent);
            }
        }

        @JavascriptInterface
        public void shareContent(String text) {
            Intent shareIntent = new Intent(Intent.ACTION_SEND);
            shareIntent.setType("text/plain");
            shareIntent.putExtra(Intent.EXTRA_TEXT, text);
            if (context instanceof Activity) {
                context.startActivity(Intent.createChooser(shareIntent, "Share via"));
            }
        }
    }
}